loop {
    let now = interval.tick().await;
    let date = Date::new();
    current_clone.set((date, now.into_std()));
}

if config.is_root() {
    ResourceDef::root_prefix(&self.mount_path)
} else {
    ResourceDef::prefix(&self.mount_path)
}

for field in &parsed {
    if !set.insert(field.serialization_name.clone()) {
        return compile_err(syn::Error::new(
            field.rust_name.span(),
            format!("Multiple fields named: `{}`", field.serialization_name),
        ));
    }
}

if let Some(id) = id.into_resettable().into_option() {
    self.requires.push(id);
} else {
    self.requires.clear();
}

if let Some(id) = id.into_resettable().into_option() {
    self.conflicts.push(id);
} else {
    self.conflicts.clear();
}

if self.member_name == self.alias {
  String::new()
} else {
  format!(" (workspace member '{}')", self.member_name)
}

if !script_src.starts_with(".") && !script_src.starts_with("/") {
  format!("./{}", script_src)
} else {
  script_src
}

if specifier.starts_with("checkin:") {
  MediaType::TypeScript
} else {
  MediaType::from_path(Path::new(&specifier))
}

if is_forbidden(signal) {
  return Err(std::io::Error::other(format!(
    "Refusing to register signal {signal}"
  )));
}

for minute in date.minute()..=59 {
  if (self.minutes & (1u64 << minute)) != 0 {
    return date.with_minute(minute);
  }
}

match dir_name.as_str() {
  "node_modules" => self.ignore_node_modules,
  ".git" => self.ignore_git_folder,
  _ => false,
}

for (key, value) in mutations
    .iter()
    .flat_map(|m| m.kind.value().map(|x| (&m.key, x)))
  {
    let key_size = check_write_key_size(key, &config)?;
    total_payload_size += check_value_size(value, &config)? + key_size;
    total_key_size += key_size;
  }

match maybe_path {
  // Always busy: simulate a database that never finishes recovering.
  Some(_) => Err(rusqlite::Error::SqliteFailure(
    rusqlite::ffi::Error::new(261),
    Some("recovering".to_string()),
  )),
  None => Ok(Connection::open_in_memory().unwrap()),
}

match base.extension() {
  None => Some(base.with_extension(extension)),
  Some(ext) => {
    let original_extension = OsStr::to_str(ext).unwrap();
    let final_extension = format!("{original_extension}.{extension}");
    Some(base.with_extension(final_extension))
  }
}

if let Some(user_agent) = http.user_agent.clone() {
    user_agent
} else {
    format!("cargo/{}", crate::version())
}

if manifest.exists() {
    Ok(manifest)
} else {
    anyhow::bail!("Could not find `{}` in `{}`", file, pwd.display())
}

match opts.krate {
    Some(ref name) => name.clone(),
    None => {
        let manifest_path = find_root_manifest_for_wd(gctx.cwd())?;
        let ws = Workspace::new(&manifest_path, gctx)?;
        ws.current()?.package_id().name().to_string()
    }
}

for entry in fs::read_dir("src/doc/man")? {
    let entry = entry?;
    let file_name = entry.file_name();
    let file_name = file_name.to_str().unwrap();
    if file_name.starts_with("cargo") && file_name.ends_with(".md") {
        src_paths.push(entry.path());
    }
}

if let Some(prev) = *target {
    cx.warn_unused_duplicate(prev, attr_span);
} else {
    *target = Some(attr_span);
}

if p.allow_normalization() && needs_normalization(self.selcx.infcx, &p) {
    p.super_fold_with(self)
} else {
    p
}

if path.as_encoded_bytes().get(2).map(|&x| is_sep_byte(x)).unwrap_or(true) {
    parse_drive(path)
} else {
    None
}

if config.hard_tabs() {
    (self.block_indent / config.tab_spaces(), self.alignment)
} else {
    (0, self.width())
}

if start < data.len() {
    for (dest, src) in out_array.iter_mut().zip(&data[start..]) {
        *dest = *src;
    }
}

if found.is_unit_return_val {
    ("", String::new())
} else {
    ("let value = ", "*".repeat(found.peel_ref_times))
}

if let ty::Closure(_, closure_subs) = typeck.expr_ty(expr).kind() {
    closure_subs.as_closure()
} else {
    return;
}

if let ExprKind::Block(block, None) = expr.kind
        && block.stmts.is_empty()
    {
        return block.expr;
    }

if comment.kind().shape.is_line() {
    line_comments_text_range(&comment)?
} else {
    comment.syntax().text_range()
}

if errs.is_empty() {
    Cow::Owned(formatted)
} else {
    panic!("Fluent errors while formatting message: {errs:?}");
}

if let VerifyBound::AllBounds(ref bs) = verify.bound
            && bs.is_empty()
        {
            return;
        }

if has_async_drops {
    insert_poll_ready_block(tcx, body)
} else {
    insert_term_block(body, TerminatorKind::Return)
}
